PlayerListener = {}

local function AddPluginEffect(pPlayer, id, name)
    local config = EffectConfig:getEffectConfig(id)
    if not config then
        LogUtil.log(string.format("AddPluginEffect not config %s", tostring(id)), LogUtil.LogLevel.Error)
        return
    end

    --local player = PlayerManager:getClientPlayer()
    --if not player then
    --    return
    --end

    local entityRenderManager = EntityRenderManager.Instance()
    if not entityRenderManager then
        LogUtil.log("AddPluginEffect not entityRenderManager", LogUtil.LogLevel.Error)
        return
    end

    local actor = entityRenderManager:getEntityActor(pPlayer)
    if not actor then
        LogUtil.log("AddPluginEffect not actor", LogUtil.LogLevel.Error)
        return
    end

    local pos = VectorUtil.newVector3(config.attachPos[1], config.attachPos[2], config.attachPos[3])
    local angle = VectorUtil.newVector3(config.attachAngle[1], config.attachAngle[2], config.attachAngle[3])
    local scale = VectorUtil.newVector3(config.attachScale[1], config.attachScale[2], config.attachScale[3])

    actor:DelPluginEffect(pPlayer:getStringProperty(name), false)
    local uuid = actor:AddPluginEffect1(name, config.attach, config.name, pos, angle, scale, 1.0, 1.0, -1, true)
    pPlayer:setStringProperty(name, uuid)

    --print(string.format("AddPluginEffect %s %s %s", name, config.attach, config.name))
end

function PlayerListener:init()
    Listener.registerCallBack(PlayUpperActionEvent, self.onPlayUpperAction)
    Listener.registerCallBack(cSyncEntityPlayerInfoEvent, self.onSyncEntityPlayerInfo)
    --Listener.registerCallBack(RefreshPlayerActorEvent, self.onRefreshPlayerActor)
    Listener.registerCallBack(RenderPlayerShowNameEvent, self.onRenderPlayerShowName)
    Listener.registerCallBack(RenderPlayerShowChatBubbleEvent, self.onRenderPlayerShowChatBubble)
    Listener.registerCallBack(EntitySkillConflictEvent, self.onEntitySkillConflict)
    Listener.registerCallBack(PlayUpperActionConflictEvent, self.onPlayUpperActionConflict)
     Listener.registerCallBack(PlayUpperActionSpecialEvent, self.onPlayUpperActionSpecial)
    BaseListener.registerCallBack(PlayerRebirthEvent, self.onPlayerRebirth)
end

function PlayerListener.onRenderPlayerShowName(pPlayer, actor, position)
    if not pPlayer or not actor then
        --print("not pPlayer or not actor")
        return true
    end

    pPlayer:setFloatProperty("PlayerShowNameOffset",  (pPlayer:getHeight() + 0.5) * actor:GetTotalScale().y - (pPlayer:getYOffset() + 0.5))

    return false
end

function PlayerListener.onRenderPlayerShowChatBubble(pPlayer, actor, position)
    if not pPlayer or not actor then
        --print("not pPlayer or not actor")
        return true
    end

    pPlayer:setFloatProperty("PlayerShowChatBubbleOffset",  (pPlayer:getHeight() + 0.8) * actor:GetTotalScale().y - (pPlayer:getYOffset() + 0.5))

    return false
end

function PlayerListener.onPlayUpperAction(skillName, holdItemId)
    if holdItemId == Define.ActionId.jiaocai then
        return false
    end

    for _, v in pairs(GameConfig.UpperActionPlaySkill) do
        if holdItemId == tonumber(v) then
            return false
        end
    end

    return true
end

function PlayerListener.onEntitySkillConflict(baseAction, upperAction, holdItemId)
    -- LogUtil.log("onEntitySkillConflict " .. holdItemId)

    if holdItemId == Define.ActionId.jiaocai then
        return false
    end

    for _, v in pairs(GameConfig.UpperActionPlaySkill) do
        if holdItemId == tonumber(v) then
            return false
        end
    end

    return true
end

function PlayerListener.onPlayUpperActionConflict(skillName, holdItemId, baseAction, upperAction)
    if baseAction == Define.AS_IDLE and upperAction ~= Define.SelectAction then
        if skillName ~= "idle" then
            return false
        end
    end
    return true
end

function PlayerListener.onPlayUpperActionSpecial(skillName)
    if skillName == "juzhong" then
        return false
    end
    return true
end

function PlayerListener.onPlayerRebirth(player)
    --player:setRenderDistanceWeight(CommonConfig.renderDistanceWeight)
    player:setIgnoreFrustumCheck(true)
    if GUIMainControl.selectMode ~= Define.SelectMode.NotSelect then
        GUIMainControl:onButtonSelect(GUIMainControl.selectMode)
    end

    if GUIMainControl.selectMode == Define.SelectMode.NotSelect then
        GUIMainControl:onButtonSelect(Define.SelectMode.Punch)
    end
end

function PlayerListener.onSyncEntityPlayerInfo(build, pPlayer)
    if not pPlayer then
        LogUtil.log("PlayerListener.onSyncEntityPlayerInfo not pPlayer", LogUtil.LogLevel.Error)
        return
    end

    local player = PlayerManager:getClientPlayer()
    if not player then
        LogUtil.log("PlayerListener.onSyncEntityPlayerInfo not player", LogUtil.LogLevel.Error)
        return
    end

    local isSelf = (player.entityId == pPlayer:hashCode())

    if build:hasParam("AdvancedLevel") then
        local advancedLevel = tonumber(build:getStringParam("AdvancedLevel"))
        if isSelf then
            player.property.advancedLevel = advancedLevel
            LogUtil.log("player.property.advancedLevel = advancedLevel " .. advancedLevel)
        end
        local advancedConfig = AdvancedConfig:getAdvancedById(advancedLevel)
        if advancedConfig then
            AddPluginEffect(pPlayer, tonumber(advancedConfig.speedEffect[1]), "SpeedEffect1")
            AddPluginEffect(pPlayer, tonumber(advancedConfig.speedEffect[2]), "SpeedEffect2")
            AddPluginEffect(pPlayer, tonumber(advancedConfig.powerEffect[1]), "PowerEffect1")
            AddPluginEffect(pPlayer, tonumber(advancedConfig.powerEffect[2]), "PowerEffect2")
        else
            LogUtil.log("AdvancedConfig not config", LogUtil.LogLevel.Error)
        end
        --print(string.format("SyncEntityPlayerInfo AdvancedLevel %s %s",
        --        tostring(pPlayer:hashCode()), build:getStringParam("AdvancedLevel")))
        RefreshPayFitnessEquipItemEvent:invoke()
    end

    if build:hasParam("Invincible") then
        local isInvincible = build:getStringParam("Invincible")
        if pPlayer then
            pPlayer:setBoolProperty("Invincible", (isInvincible == "true"))
        end
        --print(string.format("pPlayer:setBoolProperty Invincible %s %s",
        --        tostring(pPlayer:hashCode()), isInvincible))
    end

    if build:hasParam("scale#muscleMass") then
        local result = StringUtil.split(build:getStringParam("scale#muscleMass"), "#")
        local scale = tonumber(result[1])
        pPlayer:setScale(scale)
        
        if player:isBeGrab() then
            local parent = DynamicCastEntity.dynamicCastPlayer(player.Player:getParentEntity())
            if parent and pPlayer:hashCode() == parent:hashCode() then
                ClientHelper.putFloatPrefs("CameraDistanceMax", parent.m_isConcealPower and
                        GameConfig.concealPowerCameraDistanceMax or (scale * GameConfig.CameraDistanceMaxCoe))
            end
        else
            if isSelf then
                ClientHelper.putFloatPrefs("CameraDistanceMax", pPlayer.m_isConcealPower and
                        GameConfig.concealPowerCameraDistanceMax or (scale * GameConfig.CameraDistanceMaxCoe))
            end
        end

        local muscleMass = tonumber(result[2])
        pPlayer:setDoubleProperty("muscleMass", muscleMass)
    end

    if build:hasParam("ConcealPower") then
        local isConcealPower = build:getBoolParam("ConcealPower")
        pPlayer.m_isConcealPower = isConcealPower

        if player:isBeGrab() then
            local parent = DynamicCastEntity.dynamicCastPlayer(player.Player:getParentEntity())
            if parent and pPlayer:hashCode() == parent:hashCode() then
                ClientHelper.putFloatPrefs("CameraDistanceMax", parent.m_isConcealPower and
                        GameConfig.concealPowerCameraDistanceMax or (parent:getScale() * GameConfig.CameraDistanceMaxCoe))
            end
        else
            if isSelf then
                ClientHelper.putFloatPrefs("CameraDistanceMax", pPlayer.m_isConcealPower and
                        GameConfig.concealPowerCameraDistanceMax or (pPlayer:getScale() * GameConfig.CameraDistanceMaxCoe))
            end
        end

        Utility.updateCameraDistance(true)
        LogUtil.log("ClientHelper.getFloatPrefs CameraDistanceMax " .. ClientHelper.getFloatPrefs("CameraDistanceMax"))
    end

    if build:hasParam("FloatNumberDamage") then
        local result = StringUtil.split(build:getStringParam("FloatNumberDamage"), ",")
        local strFloatNumberDamage = tostring(result[1])
        local attackerId = tonumber(result[2])
        local attacker = PlayerManager:getPlayerByServerId(attackerId)
        local damage = string.format("%f", strFloatNumberDamage)
        local attackerPlayer = nil
        if attacker then
            attackerPlayer = attacker.Player
        end
        Utility.showFloatNumber(pPlayer, attackerPlayer, damage, 1)
    end

    if build:hasParam("HoldItemId") then
        pPlayer.m_holdItemId = build:getIntParam("HoldItemId")
    end

    if build:hasParam("HoldItemActor") then
        local holdItemActor = build:getStringParam("HoldItemActor")
        pPlayer.m_holdItemActor = holdItemActor
        pPlayer.m_holdItemChanged = true
    end
end

